import React from 'react';
import { useSearchParams } from 'react-router-dom';
import { useState } from 'react';
import '../../styles/Main.css';
import logo from '../../assets/logo.png';
import { useNavigate } from 'react-router-dom';
import InputField from '../../components/InputField';
import DropdownField from '../../components/DropdownField';

function UserHome() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const id = searchParams.get('id');

  const [whatAreYouEating, setWhatAreYouEating] = useState("");
  const [selectedMealTime, setSelectedMealTime] = useState('breakfast');
  const [eatingCompanion, setEatingCompanion] = useState('alone');
  const [feeling, setFeeling] = useState("");
  const [mood, setMood] = useState("mid");

  return (
    <div>
      <link href="https://fonts.googleapis.com/css2?family=Poltawski+Nowy:ital,wght@0,400..700;1,400..700&display=swap" rel="Main.css"/>
      <img src={logo} alt="Logo" className="Logo"/>
      <div className="quoteBox">
        {/* Ideally this quote switches up from a bank of quotes */}
        <p>"Recovery is not linear"</p>
      </div>
      <div className="twoBoxes">
        <div className="box">
          <h1>Meal information</h1>
          <InputField label="What are you eating?" value={whatAreYouEating} onChange={setWhatAreYouEating} />
          <DropdownField label="What meal is this?" value={selectedMealTime} onChange={setSelectedMealTime} options={[
              { value: "breakfast", label: "Breakfast" }, 
              { value: "lunch", label: "Lunch" },
              { value: "dinner", label: "Dinner" }
          ]} />
          <DropdownField label="Who are you eating with?" value={eatingCompanion} onChange={setEatingCompanion} options={[
              { value: "alone", label: "Alone" },
              { value: "family", label: "Family" },
              { value: "friends", label: "Friends" }
          ]} />
        </div> 
        <div className="box2">
          <h1>How are you?</h1>
          <div className="moodSlider">
            <button onClick={() => setMood("supersad")} className={mood === "supersad" ? "active" : ""}>
              <img src={require('../../assets/supersad.png')} alt="Super sad" />
            </button>
            <button onClick={() => setMood("sad")} className={mood === "sad" ? "active" : ""} >
              <img src={require('../../assets/sad.png')} alt="Sad" />
            </button>
            <button onClick={() => setMood("mid")} className={mood === "mid" ? "active" : ""} >
              <img src={require('../../assets/mid.png')} alt="Mid" />
            </button>
            <button onClick={() => setMood("happy")} className={mood === "happy" ? "active" : ""}>
              <img src={require('../../assets/happy.png')} alt="Happy" />
            </button>
            <button onClick={() => setMood("superhappy")} className={mood === "superhappy" ? "active" : ""}>
              <img src={require('../../assets/superhappy.png')} alt="Super happy" />
            </button>
          </div>
          <textarea 
            type={"text"} 
            value={feeling} 
            onChange={(e) => setFeeling(e.target.value)} 
          />
        </div>
      </div>
      <div className="buttonBox">
        <button onClick={() => navigate('/app')}>
          Start meal 
        </button>
      </div>
    </div>
  );
}

export default UserHome;
